#include <stdio.h>
#include <stdlib.h>
#include <string.h>
typedef struct {
    int id;
    int attr;
    int val;
    int priority;
} CSS;
int compare(const void *a, const void *b) {
    CSS *css1 = (CSS *)a;
    CSS *css2 = (CSS *)b;
    if (css1->id != css2->id) return css1->id - css2->id;
    if (css1->attr != css2->attr) return css1->attr - css2->attr;
    return css2->priority - css1->priority;
}
int main() {
    int N, M;
    scanf("%d %d", &N, &M);
    CSS *css = (CSS *)malloc(N * sizeof(CSS));
    for (int i = 0; i < N; i++) {
        scanf("%d %d %d %d", &css[i].id, &css[i].attr, &css[i].val, &css[i].priority);
    }
    qsort(css, N, sizeof(CSS), compare);
    for (int i = 0; i < M; i++) {
        int id, attr;
        scanf("%d %d", &id, &attr);
        for (int j = 0; j < N; j++) {
            if (css[j].id == id && css[j].attr == attr) {
                printf("%d\n", css[j].val);
                break;
            }
        }
    }
    free(css);
    return 0;
}

