#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;
struct CSS {
    int id;
    int attr;
    int val;
    int priority;
};
bool compare(const CSS &css1, const CSS &css2) {
    if (css1.id != css2.id) return css1.id < css2.id;
    if (css1.attr != css2.attr) return css1.attr < css2.attr;
    return css2.priority < css1.priority;
}
int main() {
    ios::sync_with_stdio(false);
    cin.tie(NULL);
    int N, M;
    cin >> N >> M;
    vector<CSS> css(N);
    for (int i = 0; i < N; i++) {
        cin >> css[i].id >> css[i].attr >> css[i].val >> css[i].priority;
    }
    sort(css.begin(), css.end(), compare);
    for (int i = 0; i < M; i++) {
        int id, attr;
        cin >> id >> attr;
        for (int j = 0; j < N; j++) {
            if (css[j].id == id && css[j].attr == attr) {
                cout << css[j].val << endl;
                break;
            }
        }
    }
    return 0;
}

code.Java:
import java.util.Arrays;
import java.util.Scanner;
public class Main {
    static class CSS implements Comparable<CSS> {
        int id;
        int attr;
        int val;
        int priority;
        public CSS(int id, int attr, int val, int priority) {
            this.id = id;
            this.attr = attr;
            this.val = val;
            this.priority = priority;
        }
        @Override
        public int compareTo(CSS o) {
            if (id != o.id) return id - o.id;
            if (attr != o.attr) return attr - o.attr;
            return o.priority - priority;
        }
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        int M = scanner.nextInt();
        CSS[] css = new CSS[N];
        for (int i = 0; i < N; i++) {
            css[i] = new CSS(scanner.nextInt(), scanner.nextInt(), scanner.nextInt(), scanner.nextInt());
        }
        Arrays.sort(css);
        for (int i = 0; i < M; i++) {
            int id = scanner.nextInt();
            int attr = scanner.nextInt();
            for (int j = 0; j < N; j++) {
                if (css[j].id == id && css[j].attr == attr) {
                    System.out.println(css[j].val);
                    break;
                }
            }
        }
    }
}

