const lines = require('fs').readFileSync(0, 'utf-8').trim().split('\n');
let i = 0;
function nextLine() {
    return lines[i++];
}
function nextInt() {
    return parseInt(nextLine());
}
function nextInts() {
    return nextLine().split(' ').map(x => parseInt(x));
}
let [N, M] = nextInts();
let css = [];
for (let i = 0; i < N; i++) {
    let [id, attr, val, priority] = nextInts();
    css.push({ id, attr, val, priority });
}
css.sort((a, b) => {
    if (a.id !== b.id) return a.id - b.id;
    if (a.attr !== b.attr) return a.attr - b.attr;
    return b.priority - a.priority;
});
for (let i = 0; i < M; i++) {
    let [id, attr] = nextInts();
    for (let j = 0; j < N; j++) {
        if (css[j].id === id && css[j].attr === attr) {
